function calculateAverage(students) {
  let total = 0;
  let count = 0;

  for (let i = 0; i < students.length; i++) {
    if (students[i].score != null) {
      total += Number(students[i].score);
      count++;
    }
  }

  if (count === 0) {
    return 0;
  }

  let average = total / count;
  return average.toFixed(2) * 1; // Convert string to number
}

